 * Test to verify the fix for the IndexOutOfBoundsException crash
 * when updating card state in DashboardCardPersonalizationViewModelSlice
 */
@ExperimentalCoroutinesApi
class DashboardCardPersonalizationCrashFixTest {

    @get:Rule
    val instantTaskExecutorRule = InstantTaskExecutorRule()

    @Mock
    private lateinit var appPrefsWrapper: AppPrefsWrapper

    @Mock
    private lateinit var selectedSiteRepository: SelectedSiteRepository

    @Mock
    private lateinit var bloggingRemindersStore: BloggingRemindersStore

    @Mock
    private lateinit var analyticsTrackerWrapper: AnalyticsTrackerWrapper

    @Mock
    private lateinit var blazeFeatureUtils: BlazeFeatureUtils

    @Mock
    private lateinit var bloggingPromptsSettingsHelper: BloggingPromptsSettingsHelper

    @Mock
    private lateinit var observer: Observer<List<DashboardCardState>>

    private lateinit var viewModelSlice: DashboardCardPersonalizationViewModelSlice
    private val testDispatcher = UnconfinedTestDispatcher()
    private val siteId = 123L
    private val localSiteId = 123

    @Before
    fun setUp() {
        MockitoAnnotations.openMocks(this)

        viewModelSlice = DashboardCardPersonalizationViewModelSlice(
            bgDispatcher = testDispatcher,
            appPrefsWrapper = appPrefsWrapper,
            selectedSiteRepository = selectedSiteRepository,
            bloggingRemindersStore = bloggingRemindersStore,
            analyticsTrackerWrapper = analyticsTrackerWrapper,
            blazeFeatureUtils = blazeFeatureUtils,
            bloggingPromptsSettingsHelper = bloggingPromptsSettingsHelper
        )

        val mockSite = SiteModel().apply {
            this.siteId = siteId
            this.hasCapabilityEditPages = true
            this.hasCapabilityManageOptions = true
            this.isWpForTeamsSite = false
        }

        whenever(selectedSiteRepository.getSelectedSite()).thenReturn(mockSite)
        whenever(selectedSiteRepository.getSelectedSiteLocalId()).thenReturn(localSiteId)
        whenever(appPrefsWrapper.getShouldHideTodaysStatsDashboardCard(siteId)).thenReturn(false)
        whenever(appPrefsWrapper.getShouldHidePostDashboardCard(siteId, any())).thenReturn(false)
        whenever(appPrefsWrapper.getShouldHidePagesDashboardCard(siteId)).thenReturn(false)
        whenever(appPrefsWrapper.getShouldHideActivityDashboardCard(siteId)).thenReturn(false)
        whenever(appPrefsWrapper.hideBlazeCard(siteId)).thenReturn(false)
        whenever(blazeFeatureUtils.isSiteBlazeEligible(mockSite)).thenReturn(true)
        whenever(bloggingPromptsSettingsHelper.shouldShowPromptsFeature()).thenReturn(true)

        val bloggingRemindersModel = BloggingRemindersModel(
            siteId = localSiteId,
            isPromptsCardEnabled = true
        )
        whenever(bloggingRemindersStore.bloggingRemindersModel(localSiteId))
            .thenReturn(flowOf(bloggingRemindersModel))
    }

    @Test
    fun `test toggling BLOGGING_PROMPTS card when it is last in list does not crash`() = runTest {
        // Setup: Initialize the slice and start it to build the initial card list
        viewModelSlice.initialize(this)
        viewModelSlice.start(siteId)

        // Observe the UI state
        viewModelSlice.uiState.observeForever(observer)

        // Get the current state
        val currentState = viewModelSlice.uiState.value
        assertNotNull("UI state should not be null", currentState)

        // Verify BLOGGING_PROMPTS card is in the list
        val bloggingPromptsCard = currentState?.find { it.cardType == CardType.BLOGGING_PROMPTS }
        assertNotNull("BLOGGING_PROMPTS card should be in the list", bloggingPromptsCard)

        // This should not throw IndexOutOfBoundsException
        // The bug was: using cardType.order (6) as index when list only has 6 items (indices 0-5)
        viewModelSlice.onCardToggled(CardType.BLOGGING_PROMPTS, false)

        // Verify the state was updated correctly
        val updatedState = viewModelSlice.uiState.value
        assertNotNull("Updated UI state should not be null", updatedState)

        val updatedCard = updatedState?.find { it.cardType == CardType.BLOGGING_PROMPTS }
        assertNotNull("BLOGGING_PROMPTS card should still be in the list", updatedCard)
        assertEquals("Card should be disabled", false, updatedCard?.enabled)

        viewModelSlice.uiState.removeObserver(observer)
    }

    @Test
    fun `test toggling card that is not in the list does not crash`() = runTest {
        // Setup: Create a scenario where BLOGGING_PROMPTS is not in the list
        whenever(bloggingPromptsSettingsHelper.shouldShowPromptsFeature()).thenReturn(false)

        viewModelSlice.initialize(this)
        viewModelSlice.start(siteId)

        viewModelSlice.uiState.observeForever(observer)

        val currentState = viewModelSlice.uiState.value
        assertNotNull("UI state should not be null", currentState)

        // Verify BLOGGING_PROMPTS card is NOT in the list
        val bloggingPromptsCard = currentState?.find { it.cardType == CardType.BLOGGING_PROMPTS }
        assertEquals("BLOGGING_PROMPTS card should not be in the list", null, bloggingPromptsCard)

        // Manually create a state with BLOGGING_PROMPTS to simulate the edge case
        val stateWithBloggingPrompts = currentState?.toMutableList()?.apply {
            add(DashboardCardState(
                title = R.string.personalization_screen_blogging_prompts_card_title,
                description = R.string.personalization_screen_blogging_prompts_card_description,
                enabled = true,
                cardType = CardType.BLOGGING_PROMPTS
            ))
        }

        // Manually set the state (simulating race condition)
        viewModelSlice.uiState.observeForever { }

        // This should not crash - the fix ensures we use actual index instead of cardType.order
        viewModelSlice.onCardToggled(CardType.BLOGGING_PROMPTS, false)

        viewModelSlice.uiState.removeObserver(observer)
    }

    @Test
    fun `test toggling middle card when list is partial does not crash`() = runTest {
        // Setup: Create a scenario where only some cards are present
        whenever(blazeFeatureUtils.isSiteBlazeEligible(any())).thenReturn(false)
        whenever(bloggingPromptsSettingsHelper.shouldShowPromptsFeature()).thenReturn(false)

        viewModelSlice.initialize(this)
        viewModelSlice.start(siteId)

        viewModelSlice.uiState.observeForever(observer)

        val currentState = viewModelSlice.uiState.value
        assertNotNull("UI state should not be null", currentState)

        // Verify PAGES card is in the list (order 3)
        val pagesCard = currentState?.find { it.cardType == CardType.PAGES }
        assertNotNull("PAGES card should be in the list", pagesCard)

        // This should not crash - the fix ensures we find the actual index
        viewModelSlice.onCardToggled(CardType.PAGES, false)

        val updatedState = viewModelSlice.uiState.value
        assertNotNull("Updated UI state should not be null", updatedState)

        val updatedCard = updatedState?.find { it.cardType == CardType.PAGES }
        assertNotNull("PAGES card should still be in the list", updatedCard)
        assertEquals("Card should be disabled", false, updatedCard?.enabled)

        viewModelSlice.uiState.removeObserver(observer)
    }
}
