import junit.framework.TestCase.assertEquals
import org.junit.Test

/**
 * Simple verification test to demonstrate that the IndexOutOfBoundsException fix works correctly.
 * 
 * This test demonstrates the bug scenario:
 * - Cards are built dynamically, so some cards may not be in the list
 * - The original code used cardType.order as the array index
 * - When BLOGGING_PROMPTS (order=6) was toggled but only 6 cards existed (indices 0-5), it crashed
 * 
 * The fix uses indexOfFirst to find the actual position in the list rather than relying on order.
 */
class DashboardCardPersonalizationIndexFixVerification {

    @Test
    fun `verify the bug scenario - order value does not match list index when cards are conditionally added`() {
        // Simulate a list where only some cards are present (like when cards are conditionally added)
        val cardList = mutableListOf(
            DashboardCardState(
                title = 1,
                description = 2,
                enabled = true,
                cardType = CardType.STATS  // order = 0
            ),
            DashboardCardState(
                title = 1,
                description = 2,
                enabled = true,
                cardType = CardType.DRAFT_POSTS  // order = 1
            ),
            DashboardCardState(
                title = 1,
                description = 2,
                enabled = true,
                cardType = CardType.SCHEDULED_POSTS  // order = 2
            ),
            // PAGES (order 3) is conditionally added - let's say it's added
            DashboardCardState(
                title = 1,
                description = 2,
                enabled = true,
                cardType = CardType.PAGES  // order = 3
            ),
            // ACTIVITY_LOG (order 4) is NOT added (conditionally excluded)
            // BLAZE (order 5) is NOT added (conditionally excluded)
            // BLOGGING_PROMPTS (order 6) is added
            DashboardCardState(
                title = 1,
                description = 2,
                enabled = true,
                cardType = CardType.BLOGGING_PROMPTS  // order = 6, but index = 4
            )
        )

        // This is what causes the bug:
        // BLOGGING_PROMPTS has order = 6, but it's at index = 4 in the list
        val bloggingPromptsOrderValue = CardType.BLOGGING_PROMPTS.order
        val actualIndexInList = cardList.indexOfFirst { it.cardType == CardType.BLOGGING_PROMPTS }

        assertEquals("BLOGGING_PROMPTS order should be 6", 6, bloggingPromptsOrderValue)
        assertEquals("But actual index in list should be 4", 4, actualIndexInList)
        assertEquals("List size should be 5", 5, cardList.size)

        // THE BUG: Trying to access cardList[6] when list size is 5 (valid indices: 0-4)
        // This would throw IndexOutOfBoundsException: Index 6 out of bounds for length 5

        // THE FIX: Use actualIndexInList instead of bloggingPromptsOrderValue
        // cardList[actualIndexInList] = updated  // This works correctly
    }

    @Test
    fun `verify indexOfFirst correctly finds card position regardless of order`() {
        val cardList = mutableListOf(
            DashboardCardState(1, 2, true, CardType.STATS),           // index 0, order 0
            DashboardCardState(1, 2, true, CardType.DRAFT_POSTS),     // index 1, order 1
            DashboardCardState(1, 2, true, CardType.SCHEDULED_POSTS), // index 2, order 2
            DashboardCardState(1, 2, true, CardType.ACTIVITY_LOG),    // index 3, order 4 (!)
            DashboardCardState(1, 2, true, CardType.BLOGGING_PROMPTS) // index 4, order 6 (!)
        )

        // The fix uses indexOfFirst to find the actual position
        val statsIndex = cardList.indexOfFirst { it.cardType == CardType.STATS }
        assertEquals("STATS should be at index 0", 0, statsIndex)

        val activityLogIndex = cardList.indexOfFirst { it.cardType == CardType.ACTIVITY_LOG }
        assertEquals("ACTIVITY_LOG should be at index 3, not order 4", 3, activityLogIndex)

        val bloggingPromptsIndex = cardList.indexOfFirst { it.cardType == CardType.BLOGGING_PROMPTS }
        assertEquals("BLOGGING_PROMPTS should be at index 4, not order 6", 4, bloggingPromptsIndex)

        // Card not in list returns -1
        val blazeIndex = cardList.indexOfFirst { it.cardType == CardType.BLAZE }
        assertEquals("BLAZE not in list should return -1", -1, blazeIndex)
    }

    @Test
    fun `verify the fix prevents IndexOutOfBoundsException`() {
        val cardList = mutableListOf(
            DashboardCardState(1, 2, true, CardType.STATS),
            DashboardCardState(1, 2, true, CardType.DRAFT_POSTS),
            DashboardCardState(1, 2, true, CardType.SCHEDULED_POSTS),
            DashboardCardState(1, 2, true, CardType.PAGES),
            DashboardCardState(1, 2, true, CardType.ACTIVITY_LOG),
            DashboardCardState(1, 2, true, CardType.BLOGGING_PROMPTS)
        )

        // Simulate the updateCardState logic with the fix
        val cardTypeToUpdate = CardType.BLOGGING_PROMPTS
        val index = cardList.indexOfFirst { it.cardType == cardTypeToUpdate }

        if (index != -1) {
            val updated = cardList[index].copy(enabled = false)
            cardList[index] = updated  // This works - uses actual index, not order

            // Verify the update worked
            assertEquals("Card should be updated", false, cardList[index].enabled)
            assertEquals("Card should still be BLOGGING_PROMPTS", CardType.BLOGGING_PROMPTS, cardList[index].cardType)
        }

        // The old buggy code would have done:
        // cardList[CardType.BLOGGING_PROMPTS.order] = updated
        // Which is: cardList[6] = updated
        // But the list only has 6 items (indices 0-5), causing IndexOutOfBoundsException
    }
}
